import { Suspense } from 'react';
import { ErrorBoundary } from './ErrorBoundary';
import { UserProfile } from './UserProfile';
import { createResource } from './createResource';

// Simulated API call — resolves after 1.5s, fails ~30% of the time
function fetchUser() {
  return new Promise<{ name: string; role: string; avatar: string }>((resolve, reject) =>
    setTimeout(
      () =>
        Math.random() < 0.3
          ? reject(new Error('Network error — user not found'))
          : resolve({ name: 'Lydia Hallie', role: 'Senior Engineer', avatar: '🧑‍💻' }),
      1500,
    ),
  );
}

let userResource = createResource(fetchUser());

export default function App() {
  return (
    <div style={{ padding: '2rem', maxWidth: '24rem' }}>
      <ErrorBoundary onRetry={() => { userResource = createResource(fetchUser()); }}>
        <Suspense fallback={
          <div style={{ padding: '1.5rem', border: '1px solid #e5e7eb', borderRadius: '0.5rem', display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
            <div style={{ width: '3rem', height: '3rem', borderRadius: '50%', background: '#e5e7eb' }} />
            <div style={{ width: '60%', height: '1rem', borderRadius: '0.25rem', background: '#e5e7eb' }} />
            <div style={{ width: '40%', height: '0.75rem', borderRadius: '0.25rem', background: '#e5e7eb' }} />
          </div>
        }>
          <UserProfile resource={userResource} />
        </Suspense>
      </ErrorBoundary>
    </div>
  );
}

