type Status = 'pending' | 'success' | 'error';

export interface Resource<T> {
  read(): T;
}

export function createResource<T>(promise: Promise<T>): Resource<T> {
  let status: Status = 'pending';
  let result: T;
  let error: unknown;

  const suspender = promise.then(
    (data) => { status = 'success'; result = data; },
    (err) => { status = 'error'; error = err; },
  );

  return {
    read(): T {
      // TODO: throw suspender if pending, throw error if error, return result if success
      return result;
    },
  };
}

starterCode.ErrorBoundary.tsx:
import { Component, type ReactNode } from 'react';

interface Props { children: ReactNode; onRetry?: () => void; }
interface State { hasError: boolean; error: Error | null; }

export class ErrorBoundary extends Component<Props, State> {
  state: State = { hasError: false, error: null };

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  handleRetry = () => {
    this.props.onRetry?.();
    this.setState({ hasError: false, error: null });
  };

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '1.5rem', border: '1px solid #fca5a5', borderRadius: '0.5rem', background: '#fef2f2' }}>
          <p style={{ color: '#dc2626', fontWeight: 600, marginBottom: '0.5rem' }}>Something went wrong</p>
          <p style={{ color: '#6b7280', fontSize: '0.875rem', marginBottom: '1rem' }}>{this.state.error?.message}</p>
          {this.props.onRetry && (
            <button onClick={this.handleRetry} style={{ padding: '0.375rem 0.75rem', borderRadius: '0.375rem', border: '1px solid #dc2626', color: '#dc2626', background: 'transparent', cursor: 'pointer' }}>Retry</button>
          )}
        </div>
      );
    }
    return this.props.children;
  }
}

