type Status = 'pending' | 'success' | 'error';

export interface Resource<T> {
  read(): T;
}

export function createResource<T>(promise: Promise<T>): Resource<T> {
  let status: Status = 'pending';
  let result: T;
  let error: unknown;

  const suspender = promise.then(
    (data) => { status = 'success'; result = data; },
    (err) => { status = 'error'; error = err; },
  );

  return {
    read(): T {
      if (status === 'pending') throw suspender; // React catches this, shows <Suspense> fallback
      if (status === 'error') throw error;       // React catches this, shows <ErrorBoundary>
      return result;                              // status === 'success'
    },
  };
}

